#include<bits/stdc++.h>
using namespace std;
int n,m;
bool vis[200010];
int fa[100010];
int T=100001,F=-100001,U=0;
int find(int x)
{
    if(x==T||x==F||x==U)
    {
        return x;
    }
    if(vis[n-x])
    {
        return U;
    }
    if(vis[n+x])
    {
        return T;
    }
    if(x>0)
    {
        if(x==fa[x])
        {
            return x;
        }
        vis[n+x]=true;
        int tmp=fa[x]=find(fa[x]);
        vis[n+x]=false;
        return tmp;
    }
    if(x==(-fa[-x]))
    {
        return x;
    }
    vis[n+x]=true;
    int tmp=find(-fa[-x]);
    vis[n+x]=false;
    return tmp;
}
int main()
{
    int c,t;
    scanf("%d%d",&c,&t);
    while(t--)
    {
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
        {
            fa[i]=i;
        }
        for(int i=1;i<=m;i++)
        {
            char ch;
            int x,y;
            cin>>ch;
            scanf("%d",&x);
            if(ch=='T')
            {
                fa[x]=T;
            }
            else if(ch=='F')
            {
                fa[x]=F;
            }
            else if(ch=='U')
            {
                fa[x]=U;
            }
            else if(ch=='+')
            {
                scanf("%d",&y);
                fa[x]=fa[y];
            }
            else
            {
                scanf("%d",&y);
                fa[x]=-fa[y];
            }
        }
        int ans=0;
        for(int i=1;i<=n;i++)
        {
            if(find(i)==U)
            {
                ans++;
            }
        }
        printf("%d\n",ans);
    }
    return 0;
}
